import { useState } from "react";

export default function QuizSection({ questions, onDone, done }) {
  const [idx, setIdx] = useState(0);
  const [selected, setSelected] = useState(null);
  const [score, setScore] = useState(0);
  const [finished, setFinished] = useState(false);

  const q = questions[idx];

  function pick(i) {
    if (selected !== null) return;
    setSelected(i);
    if (i === q.ans) setScore((s) => s + 1);
    setTimeout(() => {
      if (idx + 1 < questions.length) { setIdx((x) => x + 1); setSelected(null); }
      else setFinished(true);
    }, 1400);
  }

  if (finished) {
    const pct = Math.round((score / questions.length) * 100);
    return (
      <div className="fade-in text-center py-8">
        <div className="text-6xl mb-4">{pct >= 75 ? "🎉" : "💪"}</div>
        <h3 className="font-playfair text-2xl text-blue-900 mb-2">Quiz Complete!</h3>
        <p className="text-slate-500 text-sm mb-1">
          Score: <strong className="text-blue-900">{score}/{questions.length}</strong> ({pct}%)
        </p>
        <div className="w-full h-3 bg-slate-100 rounded-full overflow-hidden mt-3 mb-4 border border-slate-200">
          <div className="h-full bg-gradient-to-r from-blue-900 to-pink-500 rounded-full transition-all duration-1000"
            style={{ width: `${pct}%` }} />
        </div>
        {pct >= 75
          ? <p className="text-green-700 font-bold text-sm">Excellent! You're mastering it! 🌟</p>
          : <p className="text-pink-500 font-bold text-sm">Keep practicing! You'll get it! 💪</p>}
        {!done ? (
          <div className="flex justify-center mt-6">
            <button onClick={() => onDone(score)}
              className="bg-blue-900 hover:bg-blue-800 text-white font-bold px-8 py-3 rounded-xl text-sm transition-all hover:-translate-y-0.5">
              Continue →
            </button>
          </div>
        ) : <p className="text-green-700 font-bold text-sm mt-4">✓ Quiz completed!</p>}
      </div>
    );
  }

  return (
    <div className="fade-in">
      <div className="flex items-center justify-between mb-4">
        <p className="text-xs font-bold text-gray-400 uppercase tracking-wider">
          Question {idx + 1} / {questions.length}
        </p>
        <p className="text-xs font-bold text-blue-900">Score: {score}</p>
      </div>
      <div className="h-1.5 bg-slate-100 rounded-full mb-5 overflow-hidden">
        <div className="h-full bg-blue-900 rounded-full transition-all duration-300"
          style={{ width: `${((idx) / questions.length) * 100}%` }} />
      </div>
      <p className="text-lg font-extrabold text-slate-800 mb-5 leading-relaxed">{q.q}</p>
      <div className="grid grid-cols-2 gap-2.5 mb-4">
        {q.opts.map((opt, i) => {
          let cls = "text-left px-4 py-3 rounded-xl text-sm font-bold border-2 transition-all duration-200 ";
          if (selected === null) cls += "border-slate-200 bg-white text-slate-700 hover:border-blue-900 hover:bg-blue-50 cursor-pointer";
          else if (i === q.ans) cls += "border-green-500 bg-green-50 text-green-700";
          else if (i === selected) cls += "border-red-400 bg-red-50 text-red-700";
          else cls += "border-slate-100 bg-slate-50 text-slate-400 opacity-50";
          return <button key={i} className={cls} onClick={() => pick(i)} disabled={selected !== null}>{opt}</button>;
        })}
      </div>
      {selected !== null && (
        <div className={`fade-in text-sm font-bold px-4 py-3 rounded-xl border ${selected === q.ans ? "bg-green-50 border-green-200 text-green-700" : "bg-red-50 border-red-200 text-red-700"}`}>
          {selected === q.ans ? "✓ Correct! " : `✗ Correct: ${q.opts[q.ans]}. `}
          <span className="font-normal">{q.explanation}</span>
        </div>
      )}
    </div>
  );
}
